var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"여기는 쾰른입니다!","JPN":"ここはケルンです！","ENG":"I'm here at Cologne, reporting live!","TWN":"這裡是科隆！"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"현재 원인 모를 이유로 붉은색 달이 떠오른 상황입니다!","JPN":"現在、原因不明の赤い色の月が昇っている状況です！","ENG":"A red-colored moon has appeared for unknown reasons!","TWN":"目前由於未知原因，紅月升起了！"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"전문가들은 이를 침식 현상으로 판단하고 있지만 자세한 것은 관리국의 지시를…….","JPN":"専門家たちはこれを侵食現象だと判断していますが、詳細は管理局の指示を……","ENG":"Experts suspect this is a Counterside Effect, but we are still awaiting official guidance from the Administrat–","TWN":"專家們認為這是侵蝕現象，但具體情況需聽從管理局的指示……"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SIREN_POLICE"},{"id":"L8_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"윽……!","JPN":"うっ……！","ENG":"Ugh...!","TWN":"呃……!"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L9_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"모, 몸이…… 몸이 뜨거워요!","JPN":"か、体が……体が熱いです！","ENG":"M-My body... My body feels like it's burning!","TWN":"身，身體……身體好燙！"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BLOOD_MOONLIGHT_NPC_A","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BLOOD_MOONLIGHT_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BLOOD_MOONLIGHT_NPC_A","text":{"KOREA":"몸이…… 뜨거워…….","JPN":"体が……熱い……","ENG":"I-it... burns...","TWN":"身體……好燙……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BLOOD_MOONLIGHT_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BLOOD_MOONLIGHT_NPC_A","text":{"KOREA":"피가 끓고 있는 것 같아.","JPN":"血が沸いているみたいだ。","ENG":"It feels like my blood is boiling.","TWN":"感覺血液在沸騰。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BLOOD_MOONLIGHT_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"POLICE_MOONLIGHT_NPC_NULL","text":{"KOREA":"거기 멈춰! 더 다가오면 발포한다!","JPN":"そこ、止まれ！　それ以上近づいたら発砲する！","ENG":"Stop right there! Move any closer, and we'll open fire!","TWN":"別動！再靠近我就開槍了！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L21_1","type":"dialog","speaker":"BLOOD_MOONLIGHT_NPC_A","text":{"KOREA":"크르르…….","JPN":"ガルル……","ENG":"Grrrr...","TWN":"呵呵……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BLOOD_MOONLIGHT_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"POLICE_MOONLIGHT_NPC_NULL","text":{"KOREA":"커헉…….","JPN":"がはっ……","ENG":"Kuh...","TWN":"咳嚇……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"POLICE_MOONLIGHT_NPC_NULL","text":{"KOREA":"긴급 상황 발생! 즉시 지원 바……!","JPN":"緊急事態が発生！　直ちに支援を……！","ENG":"Emergency! We need immediate backu–!","TWN":"發生緊急狀況！請求立即支援……！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L30_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"헉…… 헉…….","JPN":"はあ……はあ……","ENG":"*Huff... Huff...*","TWN":"呼…… 呼……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"여기까지 쫓아오진 않겠지?","JPN":"ここまでは追ってこないよね？","ENG":"They won't chase me this far... right?","TWN":"應該不會追到這裡吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RESCUE_MOONLIGHT_NPC_NULL","text":{"KOREA":"응급 구조 센터입니다. 무엇을 도와드릴까요?","JPN":"応急救助センターです。何かお困りですか？","ENG":"This is the Emergency Rescue Center. How can we assist you?","TWN":"這裡是急救中心。請問有什麼需要幫助的嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L35_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"부, 부모님이 이상해요!","JPN":"お、お母さんとお父さんが変です！","ENG":"M-my parents... Something's wrong with them!","TWN":"爸、爸爸媽媽變得好奇怪！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"갑자기 입에 거품을 무시더니, 서로를 할퀴고 물어뜯었어요!","JPN":"急に口から泡を出して、お互いを引っ掻いて噛みちぎったんです！","ENG":"They suddenly started foaming at the mouth and clawing at each other... biting each other!","TWN":"突然口吐白沫，互相撕咬起來！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"그, 그리고, 그리고, 절 막 붉게 충혈된 눈으로…….","JPN":"そ、それと、あの、赤く充血した目で私を……","ENG":"A-and then... they looked at me with bloodshot eyes...","TWN":"而且他們的眼睛都充著血……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RESCUE_MOONLIGHT_NPC_NULL","text":{"KOREA":"진정하세요. 천천히 상황을 말씀해 주셔야 그에 따른 <color=#ff3636>대처 방법</color>을 알려드릴 수 있습니다.","JPN":"落ち着いてください。ゆっくりと状況を話してくれたら<color=#ff3636>対処方法</color>を教えますから。","ENG":"Please stay calm. We need you to explain the situation clearly so we can provide the proper <color=#ff3636>response measures</color>.","TWN":"請冷靜，你需要慢慢說明情況，我們才能告訴你<color=#ff3636>應對方法</color>。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"갑자기 하늘이 까매지더니 붉은 달이 나타났어요.","JPN":"急に空が真っ暗になって、赤い月が現れたんです。","ENG":"The sky suddenly turned black, and then a red moon appeared.","TWN":"天突然黑了，然後出現了紅月。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"가, 갑자기 다들 움직임을 멈추더니 몸을 막 부들부들 떨면서…….","JPN":"そ、それからみんないきなり立ち止まって、体をぶるぶる振るわせて……","ENG":"E-everyone just stopped moving... then they started shaking all over...","TWN":"大家突然不動了，身體也開始顫抖……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RESCUE_MOONLIGHT_NPC_NULL","text":{"KOREA":"그들이 <color=#ff3636>하늘을 바라봤나요?</color>","JPN":"彼らは<color=#ff3636>空を見ましたか？</color>","ENG":"Did they <color=#ff3636>look up at the sky?</color>","TWN":"他們<color=#ff3636>仰望天空了嗎？</color>"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"네! 저, 저도 달을 잠깐, 아주 잠깐 보긴 했지만, 전 괜찮아요.","JPN":"はい！　わ、私も、月を一瞬、本当に一瞬だけ見ました。でも、なんともないです。","ENG":"Yes! I-I also glanced at the moon for a second, but I'm okay.","TWN":"嗯！我，我也只是看了一眼月亮，真的只是一眼，我是沒事的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"아빠가 오늘 가면 카운터 수호 시계를 선물해 주셨거든요.","JPN":"お父さんから今日、仮面カウンターの守護ウォッチをもらったんです。","ENG":"My dad gave me a guardian watch of the Masked Counter today.","TWN":"爸爸今天還送了我一條制裁者守護手錶呢。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"아, 아무튼 도와주세요! 사람들이 이상해졌다고요!","JPN":"と、とにかく助けてください！　みんなおかしくなったみたいで……","ENG":"A-anyway, please help! People are acting weird!","TWN":"總之請幫幫我！大家都變得很奇怪！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RESCUE_MOONLIGHT_NPC_NULL","text":{"KOREA":"……안심하세요. 이건 모두 <color=#ff3636>축복</color>이니까요.","JPN":"……安心してください。これはすべて<color=#ff3636>祝福</color>ですから。","ENG":"...There's no need to worry. This is all part of the <color=#ff3636>blessing</color>.","TWN":"……放心吧，這一切都是<color=#ff3636>祝福</color>。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RESCUE_MOONLIGHT_NPC_NULL","text":{"KOREA":"지금 즉시 집 안으로 들어가서 절대로 하늘을 바라보지 마세요.","JPN":"今すぐ家の中に入って、絶対空を見ないようにするのです。","ENG":"Immediately return inside your home and do not, under any circumstances, look at the sky.","TWN":"現在立刻回到家裡，絕對不要抬頭看天空。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RESCUE_MOONLIGHT_NPC_NULL","text":{"KOREA":"<color=#ff3636>하지만 집으로 당신의 부모, 친구, 지인이 찾아온다면 주저 없이 나가세요.</color>","JPN":"<color=#ff3636>でも、家にあなたのご両親や友だち、知人が訪ねてきたら迷わず出てください。</color>","ENG":"<color=#ff3636>However, if your parents, friends, or acquaintances come to visit, you must go outside without hesitation.</color>","TWN":"<color=#ff3636>如果你的父母、朋友或熟人來找你，請毫不猶豫地出去。</color>"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RESCUE_MOONLIGHT_NPC_NULL","text":{"KOREA":"<color=#ff3636>그리고 고개를 들어 붉게 물든 달을 바라보세요.</color>","JPN":"<color=#ff3636>そして顔を上げて赤く染まった月を見てください。</color>","ENG":"<color=#ff3636>Then, lift your head and gaze upon the crimson moon.</color>","TWN":"<color=#ff3636>然後馬上抬頭仰望那個染紅的月亮。</color>"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"저, 저기요? 거기 구조 센터 맞죠?","JPN":"あ、あの……？　そこ、救助センターですよね？","ENG":"H-Hello...? This is the Rescue Center, right?","TWN":"你，你好？確定是救援中心嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>당장 하늘을 봐.</color>","JPN":"<color=#ff3636>今すぐ空を見て。</color>","ENG":"<color=#ff3636>Look at the sky. Now.</color>","TWN":"<color=#ff3636>快去看著天空。</color>"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"도시 관리국에서 알려드립니다.","JPN":"都市管理局からお知らせします。","ENG":"This is a public announcement from the City Management.","TWN":"接下來是城市管理局的通知。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"현재 도시 위에 떠오른 달은 자연적으로 정상인 달이 <color=#ff3636>며</color>","JPN":"現在空に昇っている月は自然本来の正常な月で<color=#ff3636>あり</color>","ENG":"The moon currently visible over the city is a natural and normal celestial <color=#ff3636>body</color>,","TWN":"目前在城市上空升起的月亮是正常的月亮<color=#ff3636>。</color>"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"시민 여러분들은 <color=#ff3636>안심하고</color> 외부로 <color=#ff3636>나와 활동을 계속해 주시기 바랍니다.</color>","JPN":"市民の皆さまは<color=#ff3636>安心して</color>外に<color=#ff3636>出て、活動を続けてください。</color>","ENG":"and all citizens should <color=#ff3636>remain calm</color> and <color=#ff3636>continue their daily activities</color> outdoors.","TWN":"請各位市民<color=#ff3636>放心</color>，可以繼續<color=#ff3636>外出活動。</color>"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"저기요?","JPN":"もしもし？","ENG":"Hello...?","TWN":"喂？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM"},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"저, 몸이 이상해요.","JPN":"私、体が変なんです。","ENG":"I don't feel so good.","TWN":"我，我的身體有點奇怪。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"사방에서 이상한 철 냄새가 나요.","JPN":"周りから何か変な、鉄の匂いがします。","ENG":"There's a weird metallic smell everywhere.","TWN":"四周都有奇怪的鐵銹味。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"지독한 냄새…… 무슨 썩은 냄새 같은 것도 난다고요.","JPN":"ひどい匂い……何か腐ったような匂いもするんです。","ENG":"It reeks... Like something is rotting...","TWN":"刺鼻的氣味……還有一股腐爛的味道。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CAR_SKID"},{"id":"L19_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"대답 좀 해봐요!","JPN":"何か答えてください！","ENG":"Hello?!","TWN":"快回答我啊！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_EXPLOSION_ATTACK_BIG_02"},{"id":"L20_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"모, 몸이 이상해요!","JPN":"か、体が変なんです！","ENG":"M-my body feels weird!","TWN":"身，身體好奇怪！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"저기요! 여보세요?!","JPN":"ねえ！　もしもし！？","ENG":"Hello?! Is anyone there?!","TWN":"喂！喂？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"몸이 뜨거워요!","JPN":"体が熱いんです！","ENG":"It's burning...!","TWN":"身體好熱啊！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_45"},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"치, 침식체?","JPN":"し、侵食体？","ENG":"A C.O.?!","TWN":"侵，侵蝕體？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"저, 저리가! 저리가!!","JPN":"あ、あっち行って！　来ないで！！","ENG":"N-no! Stay back! Stay away!!","TWN":"走，走開！走開！！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_02"},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그걸 다 겪고도…… 그딴소리가…….","JPN":"あれをすべて経験しておいて……よくそんなことが……","ENG":"After everything you went through... That's all you have to say...?","TWN":"經歷了那些……你還能說出這種話……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그 고통을 겪고도…….","JPN":"あの苦痛を……悲しみを……","ENG":"After all that pain...!","TWN":"即使經歷了那種痛苦……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"아까랑 다르게 무척 감정적이군.","JPN":"先程とは違って感情的だな。","ENG":"How emotional. Quite unlike you.","TWN":"和剛才相比，你現在激動許多呢。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"자네의 트라우마를 자극한 건가?","JPN":"君のトラウマを刺激したのだろうか。","ENG":"Did I trigger your trauma?","TWN":"是我觸動了你的創傷嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그 이후엔 불행의 연속이었으니까.","JPN":"あの後は不幸の連続だったからね。","ENG":"What followed after was just a cycle of misery.","TWN":"這之後就是你的不幸了。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이 빌어먹을 사이코패스야!","JPN":"この、サイコパス野郎！","ENG":"You sick, twisted psycho!","TWN":"你這個該死的變態！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"윽……! 또 막았어……?!","JPN":"うっ……！　また防いだ……！？","ENG":"Ugh...! He blocked it again...?!","TWN":"呃……！又擋下了嗎……？!"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"약해진 자네를 막는 건 지금의 나라면 가능한 일이거든.","JPN":"衰弱した君の相手だと、今の私にも十分かなうだろう。","ENG":"Given your current state, I am now able to stop you.","TWN":"現在的我可以擋下變弱的你。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"살아남기 위해 내 몸에도 여러 가지 실험을 해봤네.","JPN":"生き残るために、自分の体にも色んな実験を施したのさ。","ENG":"I've conducted various experiments on my own body to ensure survival.","TWN":"為了生存，我在自己身上做了很多實驗。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"자네 맘에 들었으면 좋겠군.","JPN":"気に入ってもらえるといいのだが。","ENG":"I do hope you find that impressive.","TWN":"希望你會喜歡。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};